  {st===5&&<div className="fu"><h2 style={H2}>Deadline</h2><p style={Sub}>When do you want to reach {f.gw}lbs?</p><input type="date" value={f.dl} onChange={e=>u("dl",e.target.value)} style={{...IS,colorScheme:"dark"}}/>{f.dl&&dL>0&&+f.w&&+f.gw&&(()=>{const cw=+f.w,gw=+f.gw;const isBulk=gw>cw;const tc=Math.abs(cw-gw);const wk=dL/7;const rt=tc/wk;const safeRate=isBulk?0.5:1.0;const modRate=isBulk?1.0:1.5;const fastRate=isBulk?1.5:2.0;const safe=Math.ceil(tc/safeRate)*7;const safeDate=new Date();safeDate.setDate(safeDate.getDate()+safe);const safeDateStr=safeDate.toISOString().split("T")[0];const moderate=Math.ceil(tc/modRate)*7;const modDate=new Date();modDate.setDate(modDate.getDate()+moderate);const modDateStr=modDate.toISOString().split("T")[0];return <div style={{marginTop:14}}><div style={{...BxS,padding:14}}><div style={{fontSize:13,color:"#999",lineHeight:1.8}}><strong style={{color:"#fff"}}>{dL} days</strong> to {isBulk?"gain":"lose"} <strong style={{color:isBulk?"#30d158":"#e8372c"}}>{tc} lbs</strong> — that’s <strong>{rt.toFixed(1)} lbs/week</strong></div></div>{rt>fastRate&&<div style={{...BxS,padding:14,marginTop:10,borderColor:"#e8372c30"}}><div style={{fontSize:13,fontWeight:700,color:"#e8372c",marginBottom:6}}>Unrealistic timeline</div><div style={{fontSize:12,color:"#999",lineHeight:1.6}}>{isBulk?"Gaining more than 1.5 lbs/week means most of it will be fat, not muscle. A lean bulk targets 0.5-1 lb/week to maximize muscle growth and minimize fat gain.":"Losing more than 2 lbs/week is unsafe and unsustainable. You’ll likely lose muscle, feel exhausted, and rebound. A safe rate is 1-1.5 lbs/week."}</div><div style={{display:"flex",gap:8,marginTop:10}}><button onClick={()=>u("dl",safeDateStr)} style={{...BTS,flex:1,fontSize:11,padding:10,background:"#30d158",color:"#000"}}>{isBulk?"Lean":"Safe"}: {Math.ceil(safe/7)}wk ({new Date(safeDateStr).toLocaleDateString("en-US",{month:"short",day:"numeric"})})</button><button onClick={()=>u("dl",modDateStr)} style={{...BTS,flex:1,fontSize:11,padding:10,background:"#ffd60a",color:"#000"}}>Moderate: {Math.ceil(moderate/7)}wk</button></div></div>}{rt>modRate&&rt<=fastRate&&<div style={{...BxS,padding:14,marginTop:10,borderColor:"#ffd60a30"}}><div style={{fontSize:13,fontWeight:700,color:"#ffd60a",marginBottom:6}}>{isBulk?"Fast bulk — expect some fat gain":"Aggressive but possible"}</div><div style={{fontSize:12,color:"#999",lineHeight:1.6}}>{isBulk?"At "+rt.toFixed(1)+" lbs/week, you’ll gain weight fast but a higher percentage will be fat. Consider slowing down for a leaner result.":"This is doable with discipline, but leaves little room for error. Consider a safer timeline if this is your first cut."}</div><button onClick={()=>u("dl",safeDateStr)} style={{...BTS,fontSize:11,padding:10,marginTop:8,background:"#30d158",color:"#000"}}>Switch to {isBulk?"lean":"safe"}: {Math.ceil(safe/7)} weeks</button></div>}{rt<=modRate&&rt>0&&<div style={{...BxS,padding:14,marginTop:10,borderColor:"#30d15830"}}><div style={{fontSize:13,fontWeight:700,color:"#30d158"}}>Realistic timeline ✓</div><div style={{fontSize:12,color:"#999",marginTop:4}}>{isBulk?"At "+rt.toFixed(1)+" lbs/week, this is a solid lean bulk pace. You’ll maximize muscle gain while keeping fat gain minimal.":"At "+rt.toFixed(1)+" lbs/week, this is healthy and sustainable. You can maintain muscle and energy while cutting."}</div></div>}</div>})()}{f.dl&&dL<=0&&<div style={{...BxS,padding:14,marginTop:14,borderColor:"#e8372c30"}}><div style={{fontSize:12,color:"#e8372c"}}>Pick a future date</div></div>}</div>}
